//#region extensions/qa-lab/src/cli.ts
let qaLabCliRuntimePromise = null;
async function loadQaLabCliRuntime() {
	qaLabCliRuntimePromise ??= import("./cli.runtime-Cb2cQC63.js");
	return await qaLabCliRuntimePromise;
}
async function runQaSelfCheck(opts) {
	await (await loadQaLabCliRuntime()).runQaLabSelfCheckCommand(opts);
}
async function runQaSuite(opts) {
	await (await loadQaLabCliRuntime()).runQaSuiteCommand(opts);
}
async function runQaCharacterEval(opts) {
	await (await loadQaLabCliRuntime()).runQaCharacterEvalCommand(opts);
}
async function runQaManualLane(opts) {
	await (await loadQaLabCliRuntime()).runQaManualLaneCommand(opts);
}
function collectString(value, previous) {
	const trimmed = value.trim();
	return trimmed ? [...previous, trimmed] : previous;
}
async function runQaUi(opts) {
	await (await loadQaLabCliRuntime()).runQaLabUiCommand(opts);
}
async function runQaDockerScaffold(opts) {
	await (await loadQaLabCliRuntime()).runQaDockerScaffoldCommand(opts);
}
async function runQaDockerBuildImage(opts) {
	await (await loadQaLabCliRuntime()).runQaDockerBuildImageCommand(opts);
}
async function runQaDockerUp(opts) {
	await (await loadQaLabCliRuntime()).runQaDockerUpCommand(opts);
}
async function runQaMockOpenAi(opts) {
	await (await loadQaLabCliRuntime()).runQaMockOpenAiCommand(opts);
}
function registerQaLabCli(program) {
	const qa = program.command("qa").description("Run private QA automation flows and launch the QA debugger");
	qa.command("run").description("Run the bundled QA self-check and write a Markdown report").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--output <path>", "Report output path").action(async (opts) => {
		await runQaSelfCheck(opts);
	});
	qa.command("suite").description("Run repo-backed QA scenarios against the QA gateway lane").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--output-dir <path>", "Suite artifact directory").option("--provider-mode <mode>", "Provider mode: mock-openai or live-frontier (legacy live-openai still works)", "mock-openai").option("--model <ref>", "Primary provider/model ref").option("--alt-model <ref>", "Alternate provider/model ref").option("--scenario <id>", "Run only the named QA scenario (repeatable)", collectString, []).option("--fast", "Enable provider fast mode where supported", false).action(async (opts) => {
		await runQaSuite({
			repoRoot: opts.repoRoot,
			outputDir: opts.outputDir,
			providerMode: opts.providerMode,
			primaryModel: opts.model,
			alternateModel: opts.altModel,
			fastMode: opts.fast,
			scenarioIds: opts.scenario
		});
	});
	qa.command("character-eval").description("Run the character QA scenario across live models and write a judged report").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--output-dir <path>", "Character eval artifact directory").option("--model <ref[,option]>", "Provider/model ref to evaluate; options: thinking=<level>, fast, no-fast, fast=<bool>", collectString, []).option("--scenario <id>", "Character scenario id", "character-vibes-gollum").option("--fast", "Enable provider fast mode for all candidate runs").option("--thinking <level>", "Candidate thinking default: off|minimal|low|medium|high|xhigh|adaptive").option("--model-thinking <ref=level>", "Deprecated: candidate thinking override for one model ref (repeatable)", collectString, []).option("--judge-model <ref[,option]>", "Judge provider/model ref; options: thinking=<level>, fast, no-fast, fast=<bool> (repeatable)", collectString, []).option("--judge-timeout-ms <ms>", "Override judge wait timeout", (value) => Number(value)).option("--blind-judge-models", "Hide candidate model refs from judge prompts; reports still map rankings back to real refs").option("--concurrency <count>", "Candidate model run concurrency", (value) => Number(value)).option("--judge-concurrency <count>", "Judge model run concurrency", (value) => Number(value)).action(async (opts) => {
		await runQaCharacterEval(opts);
	});
	qa.command("manual").description("Run a one-off QA agent prompt against the selected provider/model lane").requiredOption("--message <text>", "Prompt to send to the QA agent").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--provider-mode <mode>", "Provider mode: mock-openai or live-frontier (legacy live-openai still works)", "live-frontier").option("--model <ref>", "Primary provider/model ref (defaults by provider mode)").option("--alt-model <ref>", "Alternate provider/model ref").option("--fast", "Enable provider fast mode where supported", false).option("--timeout-ms <ms>", "Override agent.wait timeout", (value) => Number(value)).action(async (opts) => {
		await runQaManualLane({
			repoRoot: opts.repoRoot,
			providerMode: opts.providerMode,
			primaryModel: opts.model,
			alternateModel: opts.altModel,
			fastMode: opts.fast,
			message: opts.message,
			timeoutMs: opts.timeoutMs
		});
	});
	qa.command("ui").description("Start the private QA debugger UI and local QA bus").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--host <host>", "Bind host", "127.0.0.1").option("--port <port>", "Bind port", (value) => Number(value)).option("--advertise-host <host>", "Optional public host to advertise in bootstrap payloads").option("--advertise-port <port>", "Optional public port to advertise", (value) => Number(value)).option("--control-ui-url <url>", "Optional Control UI URL to embed beside the QA panel").option("--control-ui-token <token>", "Optional Control UI token for embedded links").option("--control-ui-proxy-target <url>", "Optional upstream Control UI target for /control-ui proxying").option("--ui-dist-dir <path>", "Optional QA Lab UI asset directory override").option("--auto-kickoff-target <kind>", "Kickoff default target (direct or channel)").option("--embedded-gateway <mode>", "Embedded gateway mode hint", "enabled").option("--send-kickoff-on-start", "Inject the repo-backed kickoff task when the UI starts", false).action(async (opts) => {
		await runQaUi(opts);
	});
	qa.command("docker-scaffold").description("Write a prebaked Docker scaffold for the QA dashboard + gateway lane").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").requiredOption("--output-dir <path>", "Output directory for docker-compose + state files").option("--gateway-port <port>", "Gateway host port", (value) => Number(value)).option("--qa-lab-port <port>", "QA lab host port", (value) => Number(value)).option("--provider-base-url <url>", "Provider base URL for the QA gateway").option("--image <name>", "Prebaked image name", "openclaw:qa-local-prebaked").option("--use-prebuilt-image", "Use image: instead of build: in docker-compose", false).option("--bind-ui-dist", "Bind-mount extensions/qa-lab/web/dist into the qa-lab container for faster UI refresh", false).action(async (opts) => {
		await runQaDockerScaffold(opts);
	});
	qa.command("docker-build-image").description("Build the prebaked QA Docker image with qa-channel + qa-lab bundled").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--image <name>", "Image tag", "openclaw:qa-local-prebaked").action(async (opts) => {
		await runQaDockerBuildImage(opts);
	});
	qa.command("up").description("Build the QA site, start the Docker-backed QA stack, and print the QA Lab URL").option("--repo-root <path>", "Repository root to target when running from a neutral cwd").option("--output-dir <path>", "Output directory for docker-compose + state files").option("--gateway-port <port>", "Gateway host port", (value) => Number(value)).option("--qa-lab-port <port>", "QA lab host port", (value) => Number(value)).option("--provider-base-url <url>", "Provider base URL for the QA gateway").option("--image <name>", "Image tag", "openclaw:qa-local-prebaked").option("--use-prebuilt-image", "Use image: instead of build: in docker-compose", false).option("--bind-ui-dist", "Bind-mount extensions/qa-lab/web/dist into the qa-lab container for faster UI refresh", false).option("--skip-ui-build", "Skip pnpm qa:lab:build before starting Docker", false).action(async (opts) => {
		await runQaDockerUp(opts);
	});
	qa.command("mock-openai").description("Run the local mock OpenAI Responses API server for QA").option("--host <host>", "Bind host", "127.0.0.1").option("--port <port>", "Bind port", (value) => Number(value)).action(async (opts) => {
		await runQaMockOpenAi(opts);
	});
}
//#endregion
export { registerQaLabCli as t };
